-- ── Icecast 2 ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Icecast 2 is a free, open-source streaming server for broadcasting live audio and video over HTTP using Ogg Vorbis, Opus, MP3 and more.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(1999, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Icecast 2 Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Icecast 2 is a free, open-source streaming media server for internet radio and video broadcasts. Explore features, setup, pricing and top alternatives in 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Icecast 2 is a free, open-source streaming media server that lets anyone broadcast live or on-demand audio and video over standard HTTP, functioning as the backbone for internet radio stations, podcasts and self-hosted media platforms worldwide. It works by accepting an encoded stream from a separate 'source client' (such as Ices, BUTT, Mixxx, Liquidsoap or ffmpeg), then relaying that stream to any number of simultaneously connected listeners through configurable mount points, each with its own format, bitrate and access rules. The project traces back to December 1998 and January 1999, when developer Jack Moffitt, working with Barath Raghavan, built the original Icecast to let Southern Methodist University's campus radio station stream audio over the university's Ethernet network after finding commercial streaming software too expensive. That first version supported only MP3. A ground-up rewrite named Icecast 2 began in 2001 to add multi-format support, better scalability and improved metadata, and shipped in January 2004; it has remained the actively maintained branch ever since, with the latest stable release, version 2.5.0, appearing in December 2025. Icecast has no venture funding, acquisition history or commercial parent company: it is stewarded as free software under the GPL-2.0 license by the Xiph.Org Foundation, the nonprofit multimedia organization founded in 2000 by Christopher 'Monty' Montgomery that also maintains Ogg Vorbis, Opus and FLAC, formats Icecast natively streams. Because it is a volunteer-driven open-source project rather than a company, Icecast has no fixed corporate headquarters or employee count; development happens through Xiph's public code repositories with community mailing lists and IRC as the primary support channels. Technically, Icecast is written in portable C, runs on Linux, BSD, macOS and Windows, and is lightweight enough to run on a Raspberry Pi while scaling, via relay and cascading configurations, to serve large distributed listener bases across multiple servers. Core features include support for MP3, AAC, Ogg Vorbis, Opus and FLAC audio plus WebM, Theora and NSV video; compatibility with the SHOUTcast source protocol so SHOUTcast-oriented encoders and directories still work; unlimited simultaneous mount points so one server instance can host many distinct streams; per-mount authentication and access control; a built-in web-based admin and status interface; optional YP ('Yellow Pages') directory listing so stations can be publicly discovered; and on-demand static file streaming alongside live broadcasts. Because Icecast is fully open source, there is no license fee, subscription or paid tier from the Xiph.Org Foundation itself - anyone can download, compile and self-host it at zero cost, and the only realistic cost comes from server bandwidth or from third-party companies that sell managed, pre-configured Icecast hosting as a convenience layer on top of the free software. Icecast's target audience spans independent and community radio stations, college broadcasters, podcasters and DJs who want to stream live sets, and developers who need an auditable, self-hostable streaming backend for products such as smart speakers or in-app radio features, rather than large commercial broadcasters who typically need turnkey SaaS support. Its principal competitors and alternatives include SHOUTcast, Liquidsoap, Wowza Streaming Engine, and hosted SaaS platforms like Radio.co, Streamguys and AzuraCast, several of which actually run Icecast under the hood but wrap it in a managed, non-technical interface. Icecast differentiates itself from these primarily by being free, vendor-neutral and fully self-hostable, at the cost of requiring more technical setup and offering no official commercial support contract.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '160ef825-4aa7-47be-8ed9-f30810cb8ba2';

