-- ── IceHrm ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$IceHrm is an affordable, self-hostable HR management platform covering attendance, leave, recruitment, payroll and performance for small teams.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Australia$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$IceHrm Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$IceHrm is a budget HR software with cloud and self-hosted options for leave, attendance, recruitment and payroll. Compare 2026 pricing and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$IceHrm is a human resource management platform built for small and mid-sized organizations that want core HRIS functionality, such as attendance and leave tracking, recruitment, payroll, performance reviews and document management, without the enterprise-level price tag of platforms like Workday or SAP SuccessFactors. The product is dual-licensed: a free, open-source, self-hostable PHP/MySQL edition that organizations can download and run on their own servers with no per-employee fee, and a managed cloud (SaaS) edition operated by the company behind the product, Ice Hrm Pty Ltd, which describes itself on its own site as 'Created in Australia.' Public information about IceHrm's exact founding date is inconsistent across sources - some trace the open-source codebase's origins to roughly 2008-2009 as a community HR project, while the commercial entity that now maintains and hosts IceHrm is documented as having been established around 2012; there is no evidence of external venture funding, and the product appears to be a bootstrapped, self-funded software business rather than one built on institutional capital or acquisitions. IceHrm's architecture centers on a modular HRIS core covering employee records, org charts and document storage, with add-on modules for time and attendance (including timesheets and shift scheduling), leave and vacation management with configurable approval workflows, an applicant tracking system for recruitment, payroll processing and payslip generation, and structured performance review cycles. The self-hosted edition gives technical teams full control of their data and lets them customize the PHP codebase, while the cloud edition removes the need for server maintenance in exchange for a per-employee monthly fee. Pricing is unusually transparent for HR software in this category: the platform is free for organizations with five or fewer employees on the cloud tier, and the most popular Cloud plan starts at 12 US dollars a month for up to six employees, scaling by roughly 1.10 to 1.54 US dollars per additional employee per month depending on plan and headcount, covering leave management, performance reviews, time tracking, recruitment, payroll and training modules with email support; the Enterprise tier moves to custom pricing and adds a dedicated account manager, payroll configuration support, data migration assistance, custom report building and priority support with a service-level agreement. IceHrm's target audience is small and medium-sized businesses, particularly those in cost-sensitive markets or with in-house IT teams who value the option to self-host and avoid vendor lock-in, as opposed to large enterprises that need deep third-party integrations and dedicated implementation teams. Its most direct competitor is OrangeHRM, another open-source HR platform with a similar free/self-hosted-plus-paid-cloud model; other alternatives that organizations evaluating IceHrm typically compare against include BambooHR and Zoho People (both cloud-only, more polished SaaS HRIS platforms aimed at similar SMB budgets), Gusto (which bundles US payroll and benefits administration more tightly than IceHrm does), and Keka (an HRMS popular in South and Southeast Asia at a comparable price point). IceHrm differentiates itself primarily on price and deployment flexibility: the combination of a genuinely free self-hosted option, a low-cost per-employee cloud tier, and an open codebase that can be audited or extended is uncommon among HR software vendors, most of which are cloud-only and charge substantially higher per-employee rates even at the entry level.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'bffd64e4-dad4-418b-a22e-4efecf3333f5';

