-- ── Iceshrimp.NET ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Iceshrimp.NET is a free, open-source ActivityPub microblogging server rewritten in .NET with Mastodon-compatible client support.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Iceshrimp.NET Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Iceshrimp.NET is an open-source, self-hosted Fediverse server built on .NET with Mastodon API support. Explore features, self-hosting and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Iceshrimp.NET is a free, open-source, self-hosted server for the ActivityPub Fediverse, the decentralized social networking protocol that also underpins Mastodon, and is designed as a complete, from-scratch rewrite of the original Iceshrimp project using the .NET platform and C# rather than the JavaScript/TypeScript stack most Fediverse servers use. It descends from a lineage of forks: Misskey, created by the Japanese developer known as syuilo starting in 2014, was forked into Calckey and later Firefish, which in mid-2023 was itself forked by a group of community developers to create the original Iceshrimp project, explicitly to prioritize stability, performance and usability fixes over adding new experimental features. Iceshrimp.NET began development shortly after as an even more ambitious effort: rather than patching the existing Firefish/Misskey-derived JavaScript codebase, the team rewrote the entire backend in C# on .NET and rebuilt the frontend using Blazor WebAssembly, aiming for a smaller resource footprint, better maintainability and higher performance than the JavaScript original, while retaining feature parity and offering a migration path for existing Iceshrimp instance administrators. As with most Fediverse server software, Iceshrimp.NET has no company behind it, no venture funding, no acquisition history and no fixed corporate headquarters; it is built and maintained by a volunteer open-source community that hosts its code and issue tracker on a self-run Forgejo instance at iceshrimp.dev rather than GitHub, and the project explicitly states an 'AI policy' restricting code contributions to human-authored work and positions itself as a deliberately non-commercial, community-centric alternative to venture-backed social platforms. Functionally, Iceshrimp.NET implements the ActivityPub standard for federation, meaning instances running the software can follow, reply to and interact with users on Mastodon, Misskey, Pleroma, Akkoma and other Fediverse-compatible servers. It also implements the Mastodon client API, so users can log in with popular third-party Mastodon apps such as Elk, Tusky and Mona rather than needing a bespoke client, a significant compatibility advantage over some other Misskey-family forks. Inherited from its Misskey lineage, it supports MFM (Misskey Flavored Markdown) for rich post formatting, emoji reactions, quote posts, and federated custom emoji, and newer builds have added features such as TOTP-based two-factor authentication, full drive and file management, federated user pronouns, proxied remote media handling by default, a rewritten MFM parser, and a configurable HTML-only public preview mode that lets posts be crawled and read without JavaScript. As self-hosted open-source software, there is no cost to run Iceshrimp.NET beyond the server infrastructure an administrator provides; there is no official managed hosting tier from the project itself, though, as with most Fediverse software, some community members run publicly joinable instances that are typically free or donation-supported. The software is still in beta as of its most recent public updates, with developers cautioning against upgrading long-running production instances until a stable release lands, and its target audience is technically inclined self-hosters, Fediverse instance administrators who prioritize server efficiency, and communities migrating away from the original JavaScript-based Iceshrimp who want the same feature set with substantially lower CPU and memory usage. Its direct competitors and alternatives include Mastodon (the largest and most widely adopted ActivityPub server), Misskey and its other forks Calckey/Firefish and Sharkey, Pleroma and its fork Akkoma, and GoToSocial, a lightweight Go-based alternative; Iceshrimp.NET differentiates itself primarily through its .NET/C# performance-oriented architecture, a design goal none of the other major Fediverse servers share, combined with Mastodon API compatibility that most Misskey-family forks lack.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'dc45a7d5-8397-4680-90b5-60974a154019';

