-- ── iCIMS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$iCIMS is an enterprise talent acquisition platform offering AI-powered applicant tracking, candidate engagement, career sites and onboarding.$q$, short_description),
  pricing_model = COALESCE($q$Enterprise$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing$q$, starting_price),
  founded_year = COALESCE(2000, founded_year),
  company_size = COALESCE($q$1,001-5,000 employees$q$, company_size),
  headquarters = COALESCE($q$Holmdel, New Jersey, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$iCIMS Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$iCIMS is an enterprise recruiting platform with AI-driven applicant tracking, CRM and onboarding. See features, custom pricing and top ATS alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$iCIMS is an enterprise-grade talent acquisition and recruiting software platform, marketed as the iCIMS Talent Cloud, that helps organizations attract, engage, hire and onboard employees through a connected suite spanning applicant tracking, candidate relationship management, career site software and onboarding tools. The company was founded around 2000 by Colin Day, who built it as an applicant tracking system before expanding it into a full talent acquisition suite, and is headquartered in Holmdel, New Jersey. iCIMS grew organically and through acquisition for nearly two decades before undergoing a major ownership change in 2018, when private equity firm Vista Equity Partners acquired a majority stake in the company; growth equity firm TA Associates joined as an additional investor in 2022. Rather than pure venture funding rounds, iCIMS's capital history is dominated by this private-equity-backed growth strategy, which funded a series of acquisitions of adjacent recruiting technology companies to build out the current Talent Cloud suite. Jason Edelboim became CEO in January 2024, succeeding earlier leadership. The company today employs roughly 1,100 to 2,000 people (LinkedIn lists a 1,001-5,000 employee band) and serves more than 4,000 organizations globally, including roughly a quarter of the Fortune 500, holding the largest market share of any dedicated applicant tracking system at around 11 percent. Architecturally, the iCIMS Talent Cloud is a cloud-based SaaS platform organized around the full talent lifecycle, commonly described across four stages: Attract (career sites, recruitment marketing and employer branding), Engage (candidate relationship management via iCIMS Engage, including AI chatbots and text and SMS engagement), Recruit/Hire (the core applicant tracking system, iCIMS Hire, with AI-assisted candidate matching, interview scheduling and offer management), and Advance (internal mobility, career pathing and workforce analytics). A separate iCIMS Onboard product handles new-hire paperwork, compliance and orientation workflows once an offer is accepted. The platform layers generative AI features across these modules for tasks like resume screening, job description generation and conversational candidate engagement. iCIMS does not publish public pricing; because it targets mid-market and enterprise organizations, typically those with 750 or more employees, pricing is quoted per deal based on modules selected, employee headcount and contract length. Third-party buyer data indicates iCIMS deals average around 20,781 US dollars per year, with a wide range from roughly 14,500 to 635,000 dollars depending on scope, per-employee-per-month rates commonly falling between 6 and 9 dollars, and separate implementation fees typically in the 15,000 to 25,000 dollar range. iCIMS's target audience is mid-market to large enterprise HR and talent acquisition teams that need an integrated, configurable recruiting ecosystem rather than a single point-solution ATS, spanning industries like healthcare, retail, financial services, manufacturing and technology. Its most commonly cited competitors and alternatives include Workday Recruiting, SAP SuccessFactors Recruiting, Oracle Taleo, Greenhouse, Lever, and SmartRecruiters; iCIMS differentiates itself from lighter-weight competitors like Greenhouse and Lever through the depth and breadth of its all-in-one suite, and from the HRIS-embedded suites like Workday and SAP SuccessFactors by being a recruiting-first specialist platform rather than a module bolted onto a broader HR system.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'af2f837c-b8e2-4cf6-bb19-100a26c709af';

