-- ── Iconosquare ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Iconosquare is an analytics-first social media management platform for scheduling, reporting and benchmarking across Instagram, TikTok and more.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Limoges, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Iconosquare Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Iconosquare is a social media analytics and scheduling platform for Instagram, TikTok, Facebook and LinkedIn. Compare 2026 pricing plans and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Iconosquare is an analytics-first social media management platform that helps brands, agencies and social media managers schedule content, measure performance and benchmark competitors across Instagram, Facebook, TikTok, LinkedIn, Twitter/X, Pinterest and YouTube. The product launched in May 2011 under the name Statigram, built initially as a simple one-page tool that surfaced ten key statistics for any public Instagram account at a time when Instagram itself offered no native analytics; Statigram grew quickly, reportedly reaching around 10 million users and ranking among the top 800 websites globally, before the company rebranded to Iconosquare in 2014 as it broadened beyond Instagram-only analytics into a fuller social media management suite covering scheduling, publishing and multi-platform reporting. Public sources do not document the individual founders' names, but the company's current leadership includes Cyrille Moreau as Chief Operating Officer and Jeremy Munoz as Chief Technology Officer. Iconosquare is headquartered in Limoges, France, with a secondary office in Berlin, Germany, and employs roughly 30 to 50 people. Rather than being built on traditional venture capital rounds, Iconosquare's recent history has been shaped by strategic acquisitions: the company became part of Wedia Group, a French digital asset and content management group, in 2022, and then transitioned into Positive, a European martech group, in 2026, reflecting a broader roll-up strategy among French marketing technology vendors. Functionally, Iconosquare's platform is built around three pillars: analytics (tracking more than 100 real-time metrics across every connected account, post and platform, including engagement, reach, follower growth, hashtag and mentions tracking, and competitor benchmarking), publishing and scheduling (a content calendar with AI-assisted caption writing and collaborative approval workflows across teams and 'groups' of accounts), and reporting (automated, customizable and white-label PDF or PowerPoint reports designed for agencies to share with clients). Pricing follows a freemium subscription model with four public tiers, billed in euros, either monthly or with a yearly discount of up to about 17 percent. The free plan covers one user and two social profiles with ten scheduled posts per profile per month and basic analytics. The Launch plan, at 33 euros per month, adds a full year of data retention, AI caption writing and covers five social profiles for one user. The Scale plan, at 69 euros per month, unlocks unlimited scheduled posts, three users (additional users cost 16 euros per month each), two years of campaign data retention, promoted-post analytics, competitor and hashtag tracking, collaboration workflows and a unified social inbox for direct messages. The Excel plan, at 116 euros per month, adds a dedicated account manager, white-label reporting, unlimited data retention, unlimited competitor benchmarking and API access for up to six users. A Custom plan, aimed at organizations needing 20 or more social profiles, offers tailored pricing with a dedicated customer success manager and enterprise-grade support. Iconosquare's target audience is social media managers, marketing teams and digital agencies that need deeper analytics and white-label client reporting than general-purpose scheduling tools provide, rather than casual individual creators. Its most direct competitors include Hootsuite, Sprout Social, Later, Buffer, Agorapulse and Sendible; Iconosquare differentiates itself from these broader social media management suites primarily through its Instagram-native analytics heritage and its depth of reporting and benchmarking data, which agencies in particular value for client-facing performance reports.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '055370e8-fd15-4fdf-9dad-531fc3b6a3c9';

