INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Leave and vacation management$q$, $q$Configurable approval workflows for time-off requests and vacation balances.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Time and attendance tracking$q$, $q$Timesheets and shift scheduling for hourly and salaried staff.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Recruitment and applicant tracking$q$, $q$Manage job postings, applicants and hiring pipelines in one system.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Payroll processing$q$, $q$Runs payroll and generates payslips alongside core HR records.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Performance reviews$q$, $q$Structured review cycles and goal tracking for employee performance management.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Document and employee record management$q$, $q$Central repository for employee documents, contracts and org charts.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Self-hosted open-source deployment$q$, $q$PHP/MySQL codebase can be installed and customized on an organization's own servers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Reporting and analytics$q$, $q$Built-in dashboards and reports across HR, attendance and payroll data.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Genuinely free tier for teams of five or fewer employees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Open-source, self-hostable codebase gives full data control$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Low per-employee cost on the cloud plan compared to most HRIS competitors$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Covers the full HR lifecycle in one product, from attendance to payroll$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$No long-term contract commitments on cloud hosting plans$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Interface and UX feel less polished than premium SaaS competitors like BambooHR$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Self-hosted edition requires PHP/MySQL server administration skills$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Limited third-party integration marketplace compared to larger HR platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Customer support is primarily email-based outside the Enterprise tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Company size and financial backing are less established than major HR SaaS vendors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Is IceHrm really free?$q$, $q$Yes, for organizations with five or fewer employees on the cloud plan, and the self-hosted open-source edition is free to download and run regardless of headcount.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Can IceHrm be self-hosted?$q$, $q$Yes, IceHrm publishes an open-source PHP/MySQL edition that organizations can install on their own servers at no license cost.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$How is cloud pricing calculated?$q$, $q$The Cloud plan starts at 12 dollars a month for up to six employees, then scales at roughly 1.10 to 1.54 dollars per additional employee per month.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Does IceHrm handle payroll?$q$, $q$Yes, payroll processing and payslip generation are included, with additional payroll configuration support available on the Enterprise tier.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Who is IceHrm best suited for?$q$, $q$Small and mid-sized organizations that want an affordable, full-featured HRIS with the option to self-host rather than a large enterprise platform.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$What support is available?$q$, $q$Email support is included on the Cloud plan, while the Enterprise tier adds a dedicated account manager and priority support with an SLA.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Affordable HRIS for Small Businesses$q$, $q$Small companies that have outgrown spreadsheets use IceHrm's Cloud plan to centralize attendance, leave and employee records without paying enterprise SaaS prices.$q$, $q$Small business owners and HR generalists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Self-Hosted HR for Data-Sensitive Organizations$q$, $q$Organizations with strict data residency or compliance requirements deploy the open-source edition on their own infrastructure to keep employee data fully in-house.$q$, $q$IT-enabled SMBs and organizations with compliance requirements$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$End-to-End Hiring and Onboarding$q$, $q$Growing teams use IceHrm's applicant tracking and performance review modules together to manage the full employee lifecycle from recruitment through review cycles.$q$, $q$HR managers and recruiting teams at SMBs$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, NULL, $q$["Up to 5 employees","Self-hosted option available","Core HR and attendance features"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Cloud$q$, $q$From $12/month$q$, $q$Monthly$q$, NULL, $q$["Up to 6 employees included, then ~$1.10-$1.54/employee","Leave, performance and time tracking","Recruitment and payroll","Email support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Dedicated account manager","Payroll configuration support","Data migration assistance","Custom report building and priority SLA support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$IceHrm is a human resource management platform aimed at small and mid-sized organizations that need core HRIS functionality, such as employee records, attendance, leave and recruitment, without the cost and complexity of enterprise HR suites. The product is offered both as a free, self-hostable open-source PHP application and as a managed cloud (SaaS) service operated by Ice Hrm Pty Ltd.$q$, $q$The platform's open-source roots give technical teams the option to install IceHrm on their own servers, customize the codebase and retain full control of employee data, while the cloud edition trades that flexibility for zero server maintenance in exchange for a low, transparent per-employee monthly fee.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$IceHrm covers the core employee lifecycle: an employee database and org chart, leave and vacation management with configurable approval chains, time and attendance tracking with timesheets, and document storage for HR records.$q$, $q$Beyond core HRIS functions, IceHrm includes an applicant tracking system for recruitment, payroll processing with payslip generation, and structured performance review cycles, letting smaller HR teams run hiring, payroll and reviews from a single platform rather than stitching together multiple point tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$IceHrm's pricing is unusually transparent for HR software: the Cloud plan is free for organizations with five or fewer employees, and the paid Cloud tier starts at 12 US dollars a month for up to six employees, scaling by roughly 1.10 to 1.54 dollars per additional employee depending on plan.$q$, $q$Organizations that outgrow the Cloud tier's self-service model can move to the Enterprise plan, which uses custom pricing and adds a dedicated account manager, payroll configuration assistance, data migration support and priority SLA-backed support, while the underlying open-source edition remains free to self-host at any company size.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bffd64e4-dad4-418b-a22e-4efecf3333f5', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
