INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$AI-powered contract authoring and review$q$, $q$Uses AI to draft, redline and review contracts against negotiated playbooks.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$Structured contract data extraction$q$, $q$Turns contract documents into structured, searchable data rather than flat files.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$Obligation and milestone management$q$, $q$Tracks key dates, deliverables and obligations across a contract portfolio.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$Compliance and risk tracking$q$, $q$Flags risky clauses and monitors compliance across thousands of active agreements.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$Clause libraries and negotiation playbooks$q$, $q$Standardizes negotiation with pre-approved clause language and fallback positions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$Analytics and reporting dashboards$q$, $q$Surfaces contract value, renewal timing and portfolio-wide risk exposure.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$Native SAP Ariba, Salesforce and Microsoft integrations$q$, $q$Embeds contract intelligence directly into existing procurement, sales and productivity workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$Enterprise-grade security and audit trails$q$, $q$Access controls and audit logging built for large, regulated organizations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$Deep, structured contract data model rather than flat document storage$q$, 0);
