INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$Strong AI and generative AI capabilities for contract review and risk detection$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$Tight native integration with SAP Ariba's procurement ecosystem$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$Well-capitalized, established vendor with a long enterprise track record$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$No public pricing; an enterprise sales cycle is required for a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$Implementation can be lengthy and resource-intensive for large rollouts$q$, 1);
