INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$What does Icertis do?$q$, $q$Icertis is an enterprise contract lifecycle management platform that helps organizations author, negotiate, store and analyze contracts using structured data and AI.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$How much does Icertis cost?$q$, $q$Icertis does not publish public pricing; cost is quoted individually based on user count, contract volume and selected modules, typically requiring a sales consultation.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$Who founded Icertis?$q$, $q$Icertis was founded in 2009 by Samir Bodas and Monish Darda in Bellevue, Washington.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$Is Icertis connected to SAP?$q$, $q$Yes, Icertis has a strategic partnership with SAP, and its product is resold as SAP Ariba Contract Intelligence by Icertis.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$What company size is Icertis built for?$q$, $q$Icertis is designed primarily for large enterprises and mid-market companies with high contract volumes, not small businesses.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$Has Icertis raised funding?$q$, $q$Yes, Icertis has raised roughly 520 million dollars total, including a 2019 round that made it a unicorn and a 150 million dollar facility secured in 2022.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$Enterprise Contract Portfolio Management$q$, $q$Large corporations use Icertis to centralize thousands of active contracts, track obligations and reduce compliance risk across global business units.$q$, $q$Enterprise legal and compliance teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$Procurement Contract Automation via SAP Ariba$q$, $q$Organizations already running SAP Ariba use the Icertis-powered Contract Intelligence module to manage supplier and procurement contracts within their existing SAP workflows.$q$, $q$Procurement and supply chain teams at SAP customers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$AI-Assisted Contract Review and Negotiation$q$, $q$Sales and legal teams use Icertis's AI contract review and clause libraries to speed up redlining, flag risky terms and standardize negotiation playbooks.$q$, $q$Sales operations and in-house legal counsel$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$Premium$q$, $q$Custom pricing$q$, $q$Annual (contact sales)$q$, NULL, $q$["Contract authoring and negotiation","Clause libraries and playbooks","Obligation and milestone tracking","Compliance and risk tracking","Core reporting and analytics"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$Premium Plus$q$, $q$Custom pricing$q$, $q$Annual (contact sales)$q$, NULL, $q$["Everything in Premium","Advanced AI-powered contract review and extraction","Enhanced collaboration tools","Expanded governance and risk analytics","Priority implementation support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Icertis is an enterprise contract lifecycle management (CLM) platform, marketed as Icertis Contract Intelligence, that helps large organizations author, negotiate, execute and analyze commercial contracts at scale. Founded in 2009 by Samir Bodas and Monish Darda and headquartered in Bellevue, Washington, the company has grown into one of the most widely used CLM platforms among Fortune 500 companies.$q$, $q$Rather than treating contracts as static documents, Icertis structures contract data so organizations can search, analyze and apply AI to obligations, risk clauses and key terms across their entire contract portfolio, and the company maintains a deep go-to-market partnership with SAP, whose Ariba procurement suite resells Icertis technology as SAP Ariba Contract Intelligence.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Icertis provides contract authoring and negotiation tools built around clause libraries and negotiation playbooks, paired with AI-powered contract review that can flag risky terms and extract obligations automatically from uploaded agreements.$q$, $q$The platform also includes obligation and milestone tracking, compliance and risk monitoring across a contract portfolio, and analytics dashboards that surface contract value, renewal timing and risk exposure, alongside native integrations with SAP Ariba, Salesforce and Microsoft business applications.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Icertis does not publish public pricing. As with most enterprise CLM software, cost depends on the number of users, contract volume, selected modules and implementation scope, and is quoted individually after a sales consultation.$q$, $q$The platform is commonly sold in edition tiers referred to as Premium and Premium Plus, with the higher tier adding more advanced AI automation, collaboration tools and governance capabilities on top of core contract management, making Icertis best suited to organizations with budget for enterprise-grade software rather than small businesses seeking a low-cost e-signature tool.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b1e19ecc-4775-4332-8779-84e45195b570', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
