INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$ActivityPub federation$q$, $q$Interoperates with Mastodon, Misskey, Pleroma, Akkoma and other Fediverse-compatible servers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$Mastodon-compatible client API$q$, $q$Works with popular Mastodon apps such as Elk, Tusky and Mona.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$.NET/C# backend$q$, $q$Engineered for a smaller resource footprint and higher performance than the original JavaScript codebase.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$Blazor WebAssembly frontend$q$, $q$Modern web frontend built for responsiveness and maintainability.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$MFM rich-text formatting$q$, $q$Supports Misskey Flavored Markdown for expressive post formatting.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$TOTP two-factor authentication$q$, $q$Adds app-based 2FA for account security.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$Federated custom emoji and quote posts$q$, $q$Retains Misskey-lineage social features across federated instances.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$HTML-only public preview$q$, $q$Configurable, JavaScript-free profile and post pages for crawlability and accessibility.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$Completely free, open-source and self-hostable$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$Significantly lower CPU and memory footprint than the original JavaScript Iceshrimp$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$Mastodon-compatible API gives access to a wide ecosystem of existing apps$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$No corporate ownership means no risk of paywalling or acquisition-driven changes$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$Active, transparent development with a human-only contribution policy$q$, 4);
