INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$No official managed hosting; requires self-hosting expertise$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$No commercial support contracts available$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$Smaller user and instance base than Mastodon, limiting network effects$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$Documentation is community-maintained and less polished than commercial platforms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$Is Iceshrimp.NET free?$q$, $q$Yes, it is free, open-source, self-hosted software with no license fees.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$Does Iceshrimp.NET work with Mastodon apps?$q$, $q$Yes, it implements the Mastodon client API, so apps like Elk, Tusky and Mona can connect to it.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$What is the difference between Iceshrimp and Iceshrimp.NET?$q$, $q$Iceshrimp.NET is a complete rewrite of the original JavaScript-based Iceshrimp in C# on .NET, built for better performance and maintainability.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$Is Iceshrimp.NET stable for production use?$q$, $q$As of its most recent releases it is still in beta, and developers recommend caution before upgrading existing production instances.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$Who maintains Iceshrimp.NET?$q$, $q$It is maintained by a volunteer open-source community, with no company or venture funding behind it.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$Can Iceshrimp.NET federate with Mastodon?$q$, $q$Yes, it implements the ActivityPub protocol, allowing federation with Mastodon, Misskey, Pleroma and other compatible servers.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$Self-Hosted Personal or Community Fediverse Server$q$, $q$Individuals and small communities self-host Iceshrimp.NET to run their own social networking instance with full control over moderation and data.$q$, $q$Self-hosting enthusiasts and small online communities$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$Resource-Efficient Instance Migration$q$, $q$Administrators running the original JavaScript Iceshrimp migrate to Iceshrimp.NET to reduce server costs while keeping the same Misskey-derived feature set.$q$, $q$Existing Fediverse instance administrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$Mastodon-App-Compatible Alternative Backend$q$, $q$Users who prefer Misskey-style features like reactions and MFM formatting but want to keep using familiar Mastodon apps run Iceshrimp.NET as their backend.$q$, $q$Fediverse users wanting Misskey features with Mastodon app support$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$Self-Hosted$q$, $q$Free$q$, $q$One-time (open source)$q$, NULL, $q$["Full source code access","Unlimited users per instance","ActivityPub federation","Mastodon-compatible client API"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$Community/Public Instances$q$, $q$Free or donation-based$q$, $q$Varies by instance operator$q$, NULL, $q$["No self-hosting required","Managed by volunteer instance admins","Feature set depends on instance version","Typically supported via donations"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Iceshrimp.NET is a free, open-source, self-hosted server for the ActivityPub Fediverse, built as a from-scratch rewrite of the original Iceshrimp project using C# and the .NET platform instead of JavaScript. It descends from Misskey by way of Calckey/Firefish and the original Iceshrimp fork created in mid-2023.$q$, $q$Unlike most Fediverse servers, Iceshrimp.NET has no company, funding or acquisition history behind it; it is built by a volunteer community that hosts its code on a self-run Forgejo instance and positions the project as a deliberately non-commercial alternative to venture-backed social networks.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Iceshrimp.NET implements the ActivityPub protocol for federation with Mastodon, Misskey, Pleroma and other compatible servers, and also implements the Mastodon client API, so popular apps like Elk, Tusky and Mona work with it out of the box.$q$, $q$Inherited from its Misskey lineage, it supports MFM rich-text formatting, emoji reactions and quote posts, and adds newer capabilities such as TOTP two-factor authentication, full drive and file management, and a configurable HTML-only public preview mode for crawlable, JavaScript-free profile pages.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$As open-source, self-hosted software, Iceshrimp.NET carries no license fee; anyone can download and run it on their own server infrastructure at no software cost, with hosting expenses being the only real cost involved.$q$, $q$There is no official managed hosting tier from the project itself, though some community operators run publicly joinable instances that are typically free to join or supported through donations rather than a formal subscription.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('dc45a7d5-8397-4680-90b5-60974a154019', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
