INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('af2f837c-b8e2-4cf6-bb19-100a26c709af', $q$How much does iCIMS cost?$q$, $q$iCIMS does not publish public pricing; buyer data suggests average annual contracts around 20,781 dollars, ranging from about 14,500 to 635,000 dollars depending on scope.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('af2f837c-b8e2-4cf6-bb19-100a26c709af', $q$What is the iCIMS Talent Cloud?$q$, $q$It is iCIMS's full recruiting suite spanning career sites and recruitment marketing (Attract), candidate engagement (Engage), applicant tracking (Hire), onboarding (Onboard) and internal mobility (Advance).$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('af2f837c-b8e2-4cf6-bb19-100a26c709af', $q$Who founded iCIMS?$q$, $q$iCIMS was founded by Colin Day around 2000 and is headquartered in Holmdel, New Jersey.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('af2f837c-b8e2-4cf6-bb19-100a26c709af', $q$Is iCIMS good for small businesses?$q$, $q$iCIMS primarily targets mid-market and enterprise organizations with 750 or more employees rather than small businesses.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('af2f837c-b8e2-4cf6-bb19-100a26c709af', $q$Does iCIMS use AI?$q$, $q$Yes, it includes AI-powered resume screening, candidate matching, chatbots and generative AI features across its Talent Cloud modules.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('af2f837c-b8e2-4cf6-bb19-100a26c709af', $q$Who owns iCIMS?$q$, $q$iCIMS has been majority-owned by private equity firm Vista Equity Partners since 2018, with TA Associates joining as an investor in 2022.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('af2f837c-b8e2-4cf6-bb19-100a26c709af', $q$High-Volume Enterprise Recruiting$q$, $q$Large employers use iCIMS Hire to manage thousands of applications across multiple business units with AI-assisted screening and standardized workflows.$q$, $q$Enterprise talent acquisition teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('af2f837c-b8e2-4cf6-bb19-100a26c709af', $q$Employer Branding and Candidate Engagement$q$, $q$Organizations use iCIMS Attract and Engage to build branded career sites and nurture passive candidates with automated, personalized outreach.$q$, $q$Recruitment marketing and employer branding teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('af2f837c-b8e2-4cf6-bb19-100a26c709af', $q$Structured New-Hire Onboarding$q$, $q$HR teams use iCIMS Onboard to digitize paperwork, compliance tasks and orientation schedules for new employees before their first day.$q$, $q$HR operations and onboarding coordinators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('af2f837c-b8e2-4cf6-bb19-100a26c709af', $q$iCIMS Hire (ATS)$q$, $q$Custom pricing$q$, $q$Annual contract$q$, NULL, $q$["AI-powered applicant tracking","Interview scheduling","Offer management","Career site integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('af2f837c-b8e2-4cf6-bb19-100a26c709af', $q$iCIMS Engage (CRM)$q$, $q$Custom pricing$q$, $q$Annual contract, add-on module$q$, NULL, $q$["Candidate relationship management","AI chatbot engagement","Text/SMS candidate messaging","Talent pipeline nurturing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('af2f837c-b8e2-4cf6-bb19-100a26c709af', $q$iCIMS Onboard$q$, $q$Custom pricing$q$, $q$Annual contract, add-on module$q$, NULL, $q$["Digital new-hire paperwork","Compliance workflows","Orientation task management","Manager onboarding checklists"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('af2f837c-b8e2-4cf6-bb19-100a26c709af', $q$Enterprise Talent Cloud Suite$q$, $q$Custom pricing$q$, $q$Annual contract$q$, NULL, $q$["Full Attract, Engage, Hire, Onboard and Advance suite","Workforce analytics","Dedicated implementation support","Enterprise SSO and integrations"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('af2f837c-b8e2-4cf6-bb19-100a26c709af', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$iCIMS is an enterprise talent acquisition platform, marketed as the iCIMS Talent Cloud, built to help mid-market and large organizations attract, engage, hire and onboard employees through a connected recruiting suite. Founded around 2000 by Colin Day and headquartered in Holmdel, New Jersey, iCIMS has grown into one of the largest dedicated applicant tracking system vendors by market share.$q$, $q$The company has been majority-owned by private equity firm Vista Equity Partners since 2018, with TA Associates joining as an investor in 2022, funding a series of acquisitions that expanded the platform from a standalone ATS into today's full Talent Cloud suite.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('af2f837c-b8e2-4cf6-bb19-100a26c709af', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Talent Cloud is organized around four stages of the talent lifecycle: Attract, covering career sites and recruitment marketing; Engage, a candidate relationship management module with AI chatbots and text messaging; and Hire, the core AI-powered applicant tracking system with interview scheduling and offer management.$q$, $q$A separate Onboard product digitizes new-hire paperwork and compliance workflows, while the Advance capability adds internal mobility, career pathing and workforce analytics, letting large employers manage recruiting and internal talent movement from one connected platform.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('af2f837c-b8e2-4cf6-bb19-100a26c709af', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$iCIMS does not publish public pricing, and is generally aimed at organizations with 750 or more employees; prospective customers must go through a sales consultation to receive a custom quote based on modules, headcount and contract length.$q$, $q$Third-party buyer data suggests average annual contracts around 20,781 US dollars, ranging from roughly 14,500 to 635,000 dollars depending on scope, with per-employee-per-month rates commonly between 6 and 9 dollars and separate implementation fees typically between 15,000 and 25,000 dollars.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('af2f837c-b8e2-4cf6-bb19-100a26c709af', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('af2f837c-b8e2-4cf6-bb19-100a26c709af', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('af2f837c-b8e2-4cf6-bb19-100a26c709af', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Distributed monitoring with high availability$q$, $q$Built-in clustering keeps monitoring running even if individual nodes fail.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$API-first architecture$q$, $q$Strong REST API supports automation and integration with external tooling.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Nagios plugin compatibility$q$, $q$Reuses the large existing library of Nagios monitoring plugins.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Icinga Web and Director$q$, $q$Web dashboard and configuration management module for managing checks at scale.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Hybrid and cloud-native monitoring$q$, $q$Covers on-premises, cloud, container and Kubernetes environments in one platform.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Third-party integrations$q$, $q$Connects with Grafana, Elastic, Graphite, InfluxDB, Terraform and Ansible.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Custom notifications and escalations$q$, $q$Configurable alerting workflows route incidents to the right responders.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Enterprise modules$q$, $q$Optional paid modules add advanced dependency visualization and reporting.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Fully free, open-source core with no artificial feature limits$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Nagios plugin compatibility eases migration for existing users$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Strong clustering and high-availability support out of the box$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Vendor-neutral, self-hosted architecture avoids SaaS lock-in$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Active development backed by a dedicated commercial entity, Icinga GmbH$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Requires self-hosting and ongoing infrastructure maintenance$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Enterprise Linux package access and premium support cost extra$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Initial setup and configuration have a learning curve versus turnkey SaaS tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Smaller ecosystem of enterprise modules compared to large commercial APM vendors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Documentation and UI, while improved over Nagios, still trail modern SaaS competitors like Datadog$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Is Icinga free?$q$, $q$Yes, the core Icinga platform is free and open source with unlimited hosts and services; paid subscriptions are optional add-ons for enterprise Linux packages, modules and support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Is Icinga a fork of Nagios?$q$, $q$Yes, Icinga was forked from Nagios in 2009 by community developers who wanted faster development and better patch acceptance.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$What is Icinga 2?$q$, $q$Icinga 2 is the current, C++-based monitoring core, a ground-up rewrite released in 2014 with clustering, a new configuration language and an API-first design.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Does Icinga support cloud and Kubernetes monitoring?$q$, $q$Yes, Icinga monitors on-premises, cloud, container and Kubernetes environments and integrates with tools like Terraform, Ansible, AWS and Azure.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Who maintains Icinga?$q$, $q$Icinga is maintained by Icinga GmbH, a company headquartered in Nuremberg, Germany, closely affiliated with NETWAYS GmbH.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$How much do Icinga's paid subscriptions cost?$q$, $q$Repository Subscriptions start around 5,000 euros per year, Module Subscriptions around 2,000 euros per year, and Support Subscriptions around 15,000 euros per year.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Migrating Off Nagios$q$, $q$Organizations running legacy Nagios deployments migrate to Icinga to keep existing plugins while gaining a modern API, clustering and web interface.$q$, $q$System administrators maintaining legacy monitoring stacks$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Hybrid and Multi-Cloud Infrastructure Monitoring$q$, $q$DevOps teams use Icinga to monitor a mix of on-premises servers, cloud services and Kubernetes clusters from one vendor-neutral platform.$q$, $q$DevOps and SRE teams managing hybrid infrastructure$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Enterprise Linux Environments Needing Guaranteed Packages$q$, $q$Enterprises running RHEL or SLES purchase the Repository Subscription for guaranteed, curated Icinga packages and add Support Subscriptions for SLA-backed assistance.$q$, $q$IT operations teams in regulated or enterprise Linux environments$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Forever Free$q$, $q$Free$q$, $q$N/A (open source)$q$, NULL, $q$["Unlimited hosts and services","Clustering and high availability","Multi-environment monitoring (on-prem, cloud, containers, Kubernetes)","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Repository Subscription$q$, $q$From EUR 5,000/year$q$, $q$Annual$q$, NULL, $q$["Curated installation packages for RHEL, SLES and Amazon Linux","Guaranteed release cadence","Enterprise Linux compatibility"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Module Subscription$q$, $q$From EUR 2,000/year$q$, $q$Annual$q$, NULL, $q$["Access to exclusive Icinga Enterprise Modules","Advanced dependency views","Upcoming Microsoft Teams and ServiceNow integrations"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$Support Subscription$q$, $q$From EUR 15,000/year$q$, $q$Annual$q$, NULL, $q$["8x5 or 24x7 professional support","Includes Repository and Module Subscriptions","Direct access to Icinga engineers"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Icinga is an open-source infrastructure monitoring platform that began in 2009 as a fork of Nagios, created by community developers, closely associated with the German consultancy NETWAYS, who wanted faster development and better acceptance of community-contributed patches than Nagios's single-maintainer model allowed.$q$, $q$The project underwent a complete rewrite released as Icinga 2 in June 2014, built in C++ with clustering, a new configuration language and an API-first design, and is now maintained by Icinga GmbH, a company headquartered in Nuremberg, Germany that operates closely alongside NETWAYS GmbH.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Icinga monitors on-premises servers, cloud services, containers and Kubernetes environments from a single vendor-neutral platform, with built-in clustering and high availability for distributed monitoring at scale, plus compatibility with existing Nagios plugins to ease migration.$q$, $q$The ecosystem includes Icinga Web for dashboards, Icinga Director for configuration management and IcingaDB for data storage, alongside integrations with Grafana, Elastic, Graphite, InfluxDB, Terraform, Ansible, AWS and Azure for teams building broader observability pipelines.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Icinga's core software is free and open source under a 'Forever Free' edition that includes unlimited hosts and services, clustering and multi-environment monitoring with no artificial feature caps.$q$, $q$Optional paid subscriptions layer on top for organizations with specific enterprise needs: Repository Subscriptions from around 5,000 euros a year for curated Enterprise Linux packages, Module Subscriptions from around 2,000 euros a year for exclusive enterprise modules, and Support Subscriptions from around 15,000 euros a year for professional 8x5 or 24x7 support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('263f6e12-dfc9-4797-a1fe-95f4616f1475', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Real-time social analytics$q$, $q$Tracks over 100 metrics across every connected account, post and platform.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Multi-platform scheduling and publishing$q$, $q$Plans and publishes content across Instagram, Facebook, TikTok, LinkedIn, X, Pinterest and YouTube.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Competitor and hashtag tracking$q$, $q$Benchmarks performance against competitors and monitors hashtag and mention activity.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$White-label reporting$q$, $q$Generates customizable, brandable PDF and PowerPoint reports for client or stakeholder use.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Unified social inbox$q$, $q$Manages direct messages and comments across platforms from one dashboard.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$AI caption writing$q$, $q$Uses AI to help draft post captions for scheduled content.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Team collaboration workflows$q$, $q$Approval processes and account groups for teams and agencies managing multiple clients.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$API access$q$, $q$Available on higher-tier plans for custom data integrations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Deep, granular analytics heritage dating back to its Instagram-only origins$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Strong white-label reporting favored by agencies for client deliverables$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Genuine free plan available, not just a trial$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Competitor and hashtag benchmarking built in at mid-tier plans$q$, 3);
