INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Recent ownership changes create some uncertainty about long-term roadmap$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Is Iconosquare free?$q$, $q$Yes, Iconosquare offers a free plan for 1 user and 2 social profiles with limited posts and basic analytics; paid plans start at 33 euros per month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$What platforms does Iconosquare support?$q$, $q$Instagram, Facebook, TikTok, LinkedIn, Twitter/X, Pinterest and YouTube.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Who owns Iconosquare?$q$, $q$Iconosquare joined Wedia Group in 2022 and became part of Positive, a European martech group, in 2026.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Is Iconosquare good for agencies?$q$, $q$Yes, its white-label reporting, client group management and competitor benchmarking are specifically aimed at agency use cases.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$What was Iconosquare originally called?$q$, $q$It launched in 2011 as Statigram, an Instagram-only statistics tool, before rebranding to Iconosquare in 2014.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Does Iconosquare offer an API?$q$, $q$Yes, API access is included on the Excel plan and above.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Agency Client Reporting$q$, $q$Digital marketing agencies use Iconosquare's white-label reports and account groups to deliver branded performance summaries to multiple clients.$q$, $q$Social media and digital marketing agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Brand Social Media Performance Tracking$q$, $q$In-house marketing teams use Iconosquare's analytics and competitor benchmarking to measure campaign performance against industry rivals.$q$, $q$Brand marketing and social media teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Multi-Platform Content Scheduling$q$, $q$Social media managers use Iconosquare's calendar and AI caption tools to plan and publish content across Instagram, TikTok, Facebook and LinkedIn from one dashboard.$q$, $q$Social media managers and content creators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, NULL, $q$["1 user","2 social profiles","10 scheduled posts per profile per month","Basic analytics and limited reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Launch$q$, $q$EUR 33/month$q$, $q$Monthly or annual (annual saves ~17%)$q$, NULL, $q$["1 user","5 social profiles","100 scheduled posts per month","1 year of data retention","AI caption writing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Scale$q$, $q$EUR 69/month$q$, $q$Monthly or annual (annual saves ~17%)$q$, NULL, $q$["3 users included","5 social profiles, 1 group","Unlimited scheduled posts","2 years of data retention","Competitor, hashtag and mentions tracking","Unified social inbox"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Excel$q$, $q$EUR 116/month$q$, $q$Monthly or annual (annual saves ~17%)$q$, NULL, $q$["6 users included","Unlimited groups","Dedicated account manager","White-label reporting","Unlimited data retention and competitor benchmarking","API access"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Iconosquare is an analytics-first social media management platform that launched in May 2011 as Statigram, a simple tool that surfaced ten key Instagram statistics before Instagram offered any native analytics of its own. The product rebranded to Iconosquare in 2014 as it expanded into scheduling, publishing and multi-platform reporting.$q$, $q$Headquartered in Limoges, France with a secondary office in Berlin, the company joined Wedia Group in 2022 and became part of the European martech group Positive in 2026, reflecting a broader consolidation trend among French marketing technology vendors.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Iconosquare tracks more than 100 real-time metrics across Instagram, Facebook, TikTok, LinkedIn, Twitter/X, Pinterest and YouTube, covering engagement, reach, follower growth, hashtag and mentions tracking, and competitor benchmarking.$q$, $q$The platform also includes a content calendar with AI-assisted caption writing, team collaboration and approval workflows, a unified inbox for direct messages, and automated, customizable, white-label reporting that agencies use for client-facing performance summaries.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Iconosquare uses a freemium model with a genuine free plan for one user and two social profiles, alongside three paid tiers: Launch at 33 euros a month, Scale at 69 euros a month, and Excel at 116 euros a month, each billed monthly or with an annual discount of up to about 17 percent.$q$, $q$Higher tiers add unlimited scheduled posts, more users, longer data retention, competitor benchmarking, white-label reporting and API access, while a Custom plan covers organizations needing 20 or more social profiles with tailored enterprise pricing and a dedicated customer success manager.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
