INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Multi-entity, multi-currency accounting$q$, $q$Supports enterprise-grade accounting across multiple legal entities and currencies from one login.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Sales and purchase order management$q$, $q$Manages the full order-to-cash and procure-to-pay cycles.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Inventory and warehouse management$q$, $q$Tracks stock levels, locations and movements across warehouses.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Manufacturing and production planning$q$, $q$Supports production orders and material planning for manufacturers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Point-of-sale (POS)$q$, $q$Built-in POS module for retail and in-store sales operations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Customer relationship management$q$, $q$Tracks customer interactions, opportunities and sales pipelines.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$OSGi plugin architecture$q$, $q$Lets developers extend the platform with custom modules without forking the core code.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Workflow automation engine$q$, $q$Built-in business process engine automates approvals and routine tasks.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Completely free, open-source core with no per-user licensing fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Broad functional coverage across ERP, CRM, SCM, MFG and POS in one integrated suite$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$OSGi plugin architecture allows customization without modifying core code$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Runs on modest server hardware while scaling to hundreds of users$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Long-running, stable codebase inherited from Compiere and ADempiere's accounting depth$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Steeper learning curve and dated UI compared to modern ERPs like Odoo$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$No official vendor support; relies on a network of independent implementation partners$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Smaller app and extension marketplace than commercial or VC-backed open-source ERPs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Requires in-house or partner technical expertise in Java and OSGi to customize$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Documentation quality and depth vary since it is community-maintained$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Is iDempiere free?$q$, $q$Yes, the core iDempiere platform is free and open source, with no license fee for self-hosting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$What is the difference between iDempiere and ADempiere?$q$, $q$iDempiere is a 2011 fork of ADempiere that introduced an OSGi plugin architecture and replaced JBoss with Apache Tomcat for better performance and a plugin-based extension model.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$What modules does iDempiere include?$q$, $q$ERP accounting, CRM, supply chain management, manufacturing, point-of-sale, inventory and workflow automation are all included in the core platform.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Who maintains iDempiere?$q$, $q$It is maintained by a global open-source community, co-founded by Carlos Ruiz and Heng Sin Low in 2011, rather than a single company.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Can iDempiere be hosted in the cloud?$q$, $q$Yes, while the core software is self-hosted, numerous implementation partners offer managed cloud hosting as a paid service.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Who is iDempiere best suited for?$q$, $q$Small and mid-sized businesses, particularly in manufacturing, distribution and retail, that want integrated ERP, CRM and SCM without proprietary licensing costs.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Integrated ERP for Manufacturing and Distribution SMBs$q$, $q$Small and mid-sized manfacturers use iDempiere to manage production planning, inventory and multi-entity accounting in one open-source system.$q$, $q$Manufacturing and distribution SMBs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Vendor-Lock-In-Free Retail and POS Operations$q$, $q$Retail businesses deploy iDempiere's point-of-sale and inventory modules to run stores without recurring per-terminal licensing fees.$q$, $q$Retail businesses and multi-location store operators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Custom ERP Extensions via OSGi Plugins$q$, $q$System integrators and in-house developers build custom modules on iDempiere's OSGi architecture to extend the ERP for industry-specific workflows without forking the core.$q$, $q$System integrators and ERP developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Community (Self-Hosted)$q$, $q$Free$q$, $q$N/A (open source)$q$, NULL, $q$["Full ERP, CRM, SCM, MFG and POS modules","Unlimited users (hardware-limited)","Community forum and documentation support","Source code access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$Partner-Hosted / Managed Cloud$q$, $q$Custom pricing (varies by partner)$q$, $q$Monthly or annual, set by implementation partner$q$, NULL, $q$["Managed hosting and infrastructure","Implementation and customization services","Training and data migration support","Ongoing maintenance and upgrades"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$iDempiere is a free, open-source Tier II ERP, CRM and supply chain management platform founded in 2011 by Carlos Ruiz and Heng Sin Low as a fork of ADempiere, itself a 2006 fork of Jorg Janke's original Compiere ERP project.$q$, $q$The defining change in iDempiere was the introduction of an OSGi-based plugin architecture, replacing JBoss with the lighter Apache Tomcat application server, which improved performance, reduced memory footprint and let developers extend the platform with custom modules without forking the core codebase.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$iDempiere covers multi-entity, multi-currency accounting, sales and purchase order management, inventory and warehouse management, manufacturing and production planning, and point-of-sale operations within a single integrated suite.$q$, $q$The platform also includes customer relationship management, a built-in workflow automation and business process engine, and a reporting and business intelligence layer, all deployable on modest server hardware while scaling to hundreds of concurrent users.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$iDempiere's core software carries no license fee: it is free and open source under a community-governed license, and any organization can download it and self-host it at zero software cost.$q$, $q$Because there is no central vendor, many independent implementation partners worldwide offer paid services layered on top of the free software, including managed cloud hosting, customization, data migration, training and ongoing support, priced individually by each partner rather than through a single company price list.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bfdc0210-d2c7-4bbc-8413-b007ecdc67e0', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
